/**
 * @fileoverview Combobox state — reactive state creation.
 * @module module/Combobox/state
 */

/**
 * Create the reactive state set for a Combobox instance.
 *
 * @param {Function}          stateFn  — razyui.state factory
 * @param {HTMLSelectElement} selectEl — native <select> element
 * @param {object}            config   — component config
 * @returns {Array} stateSet — [stateRef, setState] with .effect() method
 */
export function createReactiveState(stateFn, selectEl, config) {
    const isMultiple = selectEl.type === 'select-multiple';
    return stateFn({
        value: isMultiple ? [] : null,
        options: [],
        open: false,
        disabled: selectEl.disabled,
        readonly: selectEl.hasAttribute('readonly'),
        placeholder: config.placeholder || '',
        filterText: '',
        checked: config.checkbox ? {} : null,
    });
}
