/**
 * @fileoverview Shared z-index scale — single source of truth for stacking.
 *
 * Provides a centralized layering system to prevent ad-hoc z-index conflicts
 * across components. Each layer is named and consistently spaced.
 *
 * @module shared/tokens/z-index
 */

// ── Z-Index Scale ────────────────────────────
// Layers are spaced by 100 to allow fine-grained insertions within a band.

/** Dropdown / tooltip floaters — sits above normal content. */
export const Z_DROPDOWN = 9000;

/** Darkroom overlays (ClipBox, Combobox expanded view). */
export const Z_DARKROOM = 9100;

/** Floating windows — dynamic stacking with nextZ(). */
export const Z_FLOATING_WINDOW = 9900;

/** Dialog / modal overlays — highest interactive layer. */
export const Z_DIALOG = 10000;

/** Combobox dropdown when rendered above a dialog. */
export const Z_DIALOG_DROPDOWN = 10001;

/** Snap overlay for FloatingWindow. */
export const Z_SNAP_OVERLAY = 9998;

/** Full-screen takeover layers (e.g., Lightbox, BlockEditor full-screen). */
export const Z_FULLSCREEN = 99999;

/** Developer tools panel. */
export const Z_DEV = 999999;
