/**
 * @fileoverview Combobox events — centralised event binding via AbortController.
 * @module module/Combobox/events
 */

import razyui from '../../index.js';
import { CLS, DEFAULTS } from './constants.js';

/**
 * Bind static event listeners for Combobox DOM elements.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {object} domRefs  — { container, optionsList, expandBtn? }
 * @param {object} handlers — { onContainerClick, onOptionClick, onExpandClick? }
 * @returns {AbortController}
 */
export function bindEvents(domRefs, handlers) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    razyui(domRefs.container).on('click', handlers.onContainerClick, opts);
    razyui(domRefs.optionsList).on('click', handlers.onOptionClick, opts);

    if (handlers.onCheckboxClick) {
        razyui(domRefs.optionsList).on('click', handlers.onCheckboxClick, { selector: '.' + CLS.CHECKBOX, signal: ac.signal });
    }

    if (domRefs.expandBtn) {
        razyui(domRefs.expandBtn).on('click', handlers.onExpandClick, opts);
    }

    return ac;
}

/**
 * Attach document-level outside-click, scroll, resize, and Escape key listeners.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {HTMLElement} containerEl — .combobox-container element
 * @param {HTMLElement} floatingEl  — .combobox-floating element
 * @param {Function}    onClose     — callback invoked when closing
 * @returns {AbortController}
 */
export function attachOutsideClick(containerEl, floatingEl, onClose) {
    const ac = new AbortController();
    const signal = ac.signal;
    const attachedAt = performance.now();
    const GUARD_MS = DEFAULTS.guardMs; // ignore events within guard window to avoid race conditions

    razyui(document).on('mousedown', (e) => {
        if (performance.now() - attachedAt < GUARD_MS) return;
        if (containerEl.contains(e.target) || floatingEl.contains(e.target)) {
            return;
        }
        onClose();
    }, { signal });

    // Close on scroll (but not if scrolling inside the dropdown) / resize
    razyui(document).on('scroll', (e) => {
        if (performance.now() - attachedAt < GUARD_MS) return;
        if (floatingEl.contains(e.target)) return;
        onClose();
    }, { signal, capture: true });

    razyui(window).on('resize', () => {
        if (performance.now() - attachedAt < GUARD_MS) return;
        onClose();
    }, { signal });

    // Close on Escape
    razyui(document).on('keydown', (e) => {
        if (e.key === 'Escape') {
            onClose();
        }
    }, { signal });

    return ac;
}

/**
 * Bind mousedown on darkroom overlay to close when clicking outside the panel.
 *
 * @param {HTMLElement} overlay — darkroom overlay element
 * @param {Function}    onClose — callback invoked on outside click
 */
export function bindDarkroomClose(overlay, onClose) {
    razyui(overlay).on('mousedown', (e) => {
        if (e.target === overlay) onClose();
    });
}
